// Bundles questions/*.json into main/questions-data.js, a plain script-loadable
// JS file. The app loads quiz data via <script src="questions-data.js">
// instead of fetch(), so it works when interactiveQuiz.html is opened directly
// (file:// protocol) and not just when served over http(s) — browsers block
// fetch() of local files for security reasons, but a <script> tag has no such
// restriction.
//
// Run this after editing any file in questions/:
//   node scripts/bundle-questions.js

const fs = require('fs');
const path = require('path');

const questionsDir = path.join(__dirname, '..', 'questions');
const outFile = path.join(__dirname, '..', 'main', 'questions-data.js');

const files = fs.readdirSync(questionsDir).filter((f) => f.endsWith('.json'));

const bundle = {};
for (const file of files) {
  const subject = path.basename(file, '.json');
  bundle[subject] = JSON.parse(fs.readFileSync(path.join(questionsDir, file), 'utf8'));
}

const out = `// Auto-generated by scripts/bundle-questions.js from questions/*.json — do not edit by hand.
// Regenerate with: node scripts/bundle-questions.js
window.QUIZ_DATA = ${JSON.stringify(bundle, null, 2)};
`;

fs.writeFileSync(outFile, out);
console.log(`Bundled ${files.length} subjects into ${path.relative(process.cwd(), outFile)}`);
